from flask import Flask, request, jsonify
import logging
import logging.handlers
from werkzeug.security import generate_password_hash, check_password_hash
import datetime

app = Flask(__name__)

# Create a rotating log handler to store logs in application.log file
logger = logging.getLogger()
logger.setLevel(logging.INFO)
handler = logging.handlers.RotatingFileHandler('application.log', maxBytes=10485760, backupCount=5)
formatter = logging.Formatter('%(asctime)s - %(levelname)s - %(message)s')
handler.setFormatter(formatter)
logger.addHandler(handler)

# User database
users = {
    'user1': generate_password_hash('password123'),
    'user2': generate_password_hash('password456')
}

@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username')
    password = request.json.get('password')
    
    if username in users and check_password_hash(users[username], password):
        logger.info(f'Login successful for user {username}')
        return jsonify({'message': 'Login successful'}), 200
    else:
        logger.warning(f'Login failed for user {username} with IP address {request.remote_addr} and User Agent {request.user_agent.string}')
        return jsonify({'message': 'Login failed'}), 401

if __name__ == '__main__':
    app.run(debug=True)